class Solution(object):
    def shiftDistance(self, s, t, nextCost, previousCost):
        # Precompute prefix sums for forward and backward costs (doubled alphabet for wrap)
        # forward_prefix[i] = cumulative next cost from 'a' to index i
        fwd = [0] * 27
        for i in range(26):
            fwd[i + 1] = fwd[i] + nextCost[i]
        # For wraparound, double the array
        fwd2 = fwd[1:] + [fwd[26] + x for x in fwd[1:]]

        bwd = [0] * 27
        for i in range(26):
            bwd[i + 1] = bwd[i] + previousCost[25 - i]

        ans = 0
        for si, ti in zip(s, t):
            a = ord(si) - ord('a')
            b = ord(ti) - ord('a')
            if a == b:
                continue
            # Forward: go from a to b stepping nextCost[a], nextCost[a+1], ...
            if b > a:
                fwd_cost = fwd[b] - fwd[a]
            else:
                fwd_cost = fwd[26] - fwd[a] + fwd[b]
            # Backward: go from a to b stepping previousCost[a], previousCost[a-1], ...
            if a > b:
                bwd_cost = sum(previousCost[(a - i) % 26] for i in range(a - b))
            else:
                bwd_cost = sum(previousCost[(a - i) % 26] for i in range(26 - (b - a)))
            ans += min(fwd_cost, bwd_cost)
        return ans
